INSERT OR IGNORE INTO faction(id, eid, game_id, name, key, description, version,
                              created_by_sub, created_at, updated_at, deleted_at)
VALUES
  (1, '35dd38fa-2bcc-4492-8f58-a106d0d02cbb', 1, 'The Empire', 'empire', 'The greatest human realm of the Old World, fielding disciplined soldiers, war machines, and battle wizards of the Colleges of Magic.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (2, 'f0000002-0000-4000-8000-000000000000', 1, 'Beastmen', 'beastmen', 'Savage mutants of the forests who despise all civilisation, uniting under powerful Bray-Shamans and Doombulls to bring ruin to mortal realms.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (3, 'f0000003-0000-4000-8000-000000000000', 1, 'Bretonnia', 'bretonnia', 'A chivalric human kingdom inspired by the Lady of the Lake, whose knights are among the finest cavalry in the Old World.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (4, 'f0000004-0000-4000-8000-000000000000', 1, 'Chaos Dwarfs', 'chaos-dwarfs', 'Dark and industrious Dawi Zharr who forge daemonic war machines and enslave countless races to fuel their infernal empire in the Mountains of Mourn.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (5, 'f0000005-0000-4000-8000-000000000000', 1, 'Daemons of Chaos', 'daemons-of-chaos', 'Entities of pure Chaos drawn from the Realm of Chaos, serving all four Dark Gods in one fell warhost of boundless malevolence.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (6, 'f0000006-0000-4000-8000-000000000000', 1, 'Dark Elves', 'dark-elves', 'Cruel and ruthless Druchii of Naggaroth who raid the world for slaves and glory, wielding cold-blooded cruelty and powerful magic in equal measure.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (7, 'f0000007-0000-4000-8000-000000000000', 1, 'Dwarfs', 'dwarfs', 'The proud and stubborn Dawi of the mountain holds, whose unbreakable resilience, master craftsmanship, and thunderous artillery have held back darkness for millennia.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (8, 'f0000008-0000-4000-8000-000000000000', 1, 'Grand Cathay', 'grand-cathay', 'The vast and ancient empire of the East, guarded by the Great Bastion and the harmonious forces of the Celestial Dragon Emperor.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (9, 'f0000009-0000-4000-8000-000000000000', 1, 'Greenskins', 'greenskins', 'Ever-warring tribes of Orcs and Goblins whose lust for the Waaagh! drives them to conquer and smash everything in their path.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (10, 'f000000a-0000-4000-8000-000000000000', 1, 'High Elves', 'high-elves', 'The noble Asur of Ulthuan, ancient guardians of civilisation who wield unparalleled magical power and the finest warriors and ships in the world.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (11, 'f000000b-0000-4000-8000-000000000000', 1, 'Khorne', 'khorne', 'The Bloodbound servants of the Blood God, who reject all sorcery and seek only endless slaughter to fill the skull throne of their wrathful deity.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (12, 'f000000c-0000-4000-8000-000000000000', 1, 'Kislev', 'kislev', 'The northernmost human kingdom, a land of fierce warriors and powerful Ice Magic standing as the first bulwark against the forces of Chaos.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (13, 'f000000d-0000-4000-8000-000000000000', 1, 'Lizardmen', 'lizardmen', 'The ancient Slann Mage-Priests and their Saurus and Skink servants striving to enact the Great Plan of the Old Ones.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (14, 'f000000e-0000-4000-8000-000000000000', 1, 'Norsca', 'norsca', 'Fierce Norse warriors who worship the Chaos Gods and raid the world, hardened by the brutal north and riding mammoths into battle.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (15, 'f000000f-0000-4000-8000-000000000000', 1, 'Nurgle', 'nurgle', 'The rotting servants of the Plague God, who spread pestilence and decay across the world with cheerful inevitability and bloated resilience.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (16, 'f0000010-0000-4000-8000-000000000000', 1, 'Ogre Kingdoms', 'ogre-kingdoms', 'Massive and powerful Ogre mercenaries of the Mountains of Mourn, motivated entirely by their insatiable hunger and love of gold.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (17, 'f0000011-0000-4000-8000-000000000000', 1, 'Skaven', 'skaven', 'The rat-men of the Under-Empire, who plot tirelessly in the shadows and unleash horrible warp-powered war machines and endless plague upon their foes.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (18, 'f0000012-0000-4000-8000-000000000000', 1, 'Slaanesh', 'slaanesh', 'The devoted of the Prince of Pleasure, who pursue excess and sensation to extremes, moving with supernatural speed and grace to overwhelm their foes.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (19, 'f0000013-0000-4000-8000-000000000000', 1, 'Tomb Kings', 'tomb-kings', 'Skeletal rulers of ancient Nehekhara reawakened to reclaim their former glory, commanding vast undead legions and colossal constructs of stone and bone.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (20, 'f0000014-0000-4000-8000-000000000000', 1, 'Tzeentch', 'tzeentch', 'The ever-changing followers of the Architect of Fate, wielding devastating magic and mutation to reshape reality in service of their inscrutable lord.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (21, 'f0000015-0000-4000-8000-000000000000', 1, 'Vampire Coast', 'vampire-coast', 'Undead pirates who haunt the seas of the world, led by Vampire Counts who command zombie crews, sea monsters, and explosive gunpowder weapons.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (22, 'f0000016-0000-4000-8000-000000000000', 1, 'Vampire Counts', 'vampire-counts', 'Ancient undead rulers of Sylvania who raise the dead to fight for them, wielding potent necromancy and the terror of the night.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (23, 'f0000017-0000-4000-8000-000000000000', 1, 'Warriors of Chaos', 'warriors-of-chaos', 'The mortal servants of the Chaos Gods who pour south from the Chaos Wastes, armoured in dark iron and sworn to tear down civilisation in their masters'' names.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (24, 'f0000018-0000-4000-8000-000000000000', 1, 'Wood Elves', 'wood-elves', 'The eternal guardians of Athel Loren, who defend their forest home with unmatched skill in archery, swift cavalry, and the ancient power of the forest spirits.',
   1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null);
